public class Summer {
    static int total = 0;

    public static int addUp(int[] nums) {
        int total = 0;          // shadows the static field
        for (int n : nums) total += n;
        return total;
    }

    public static void main(String[] args) {
        addUp(new int[]{1, 2, 3});
        System.out.println(total);   // prints static field, which is still 0
    }
}
